import { useState } from "react";

// ═══════════════════════════════════════════
// DESIGN TOKENS — Apple Health-inspired
// ═══════════════════════════════════════════
const t = {
  bg:"#F2F2F7",fg:"#0D1619",muted:"#6B7280",accent:"#FF751F",
  accentLight:"#FFF0E6",ctaBg:"#0D1619",ctaText:"#FFFFFF",
  ctaDisabled:"#B0B0B0",divider:"#E5E5EA",surface:"#FFFFFF",
  callout:"#FFF9E6",success:"#22C55E",successLight:"#F0FDF4",
  warning:"#F5A623",border:"#D1D5DB",borderLight:"#E5E7EB",
  dangerLight:"#FEF2F2",danger:"#EF4444",card:"#FFFFFF",
  gradTop:"#D45400",gradMid:"#E87020",gradBot:"#F2F2F7",
};
const f = "'Manrope',system-ui,sans-serif";

// Warm gradient — dark burnt orange top for white text contrast, fading to system gray
const grad = `linear-gradient(180deg, ${t.gradTop} 0%, ${t.gradMid} 40%, #F09050 65%, #F5C4A0 82%, ${t.gradBot} 100%)`;

// ═══════════════════════════════════════════
// SHARED COMPONENTS
// ═══════════════════════════════════════════
function Phone({children,screen,setScreen,screenList,labels}) {
  return (
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:"1rem",width:"100%",maxWidth:"420px"}}>
      <div style={{width:"100%",maxWidth:"390px",height:"844px",borderRadius:"44px",background:t.bg,border:"1px solid #D1D1D6",overflow:"hidden",position:"relative",boxShadow:"0 20px 60px -15px rgba(0,0,0,0.15)"}}>
        <div style={{height:"54px",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 32px",fontSize:"15px",fontWeight:600,color:"#fff",fontFamily:f,position:"relative",zIndex:10}}>
          <span>9:41</span>
          <div style={{position:"absolute",top:"12px",left:"50%",transform:"translateX(-50%)",width:"126px",height:"34px",borderRadius:"17px",background:"#000"}}/>
          <div style={{display:"flex",gap:"5px",alignItems:"center"}}>
            <svg width="17" height="12" viewBox="0 0 17 12"><rect x="0" y="4" width="3" height="8" rx="1" fill="#fff"/><rect x="4.5" y="2.5" width="3" height="9.5" rx="1" fill="#fff"/><rect x="9" y="1" width="3" height="11" rx="1" fill="#fff"/><rect x="13.5" y="0" width="3" height="12" rx="1" fill="#fff"/></svg>
            <svg width="25" height="12" viewBox="0 0 25 12"><rect x="0" y="1" width="22" height="10" rx="2.5" stroke="#fff" strokeWidth="1" fill="none"/><rect x="23" y="3.5" width="2" height="5" rx="1" fill="#fff" opacity="0.4"/><rect x="1.5" y="2.5" width="16" height="7" rx="1.5" fill="#fff"/></svg>
          </div>
        </div>
        <div style={{height:"calc(100% - 54px)",overflow:"hidden",position:"relative"}}>{children}</div>
      </div>
      <div style={{display:"flex",flexWrap:"wrap",gap:"4px",justifyContent:"center",maxWidth:"400px"}}>
        {screenList.map(s=><button key={s} onClick={()=>setScreen(s)} style={{padding:"4px 11px",borderRadius:"9999px",border:"none",fontSize:"10.5px",fontFamily:f,fontWeight:screen===s?700:500,background:screen===s?t.fg:"#E5E5EA",color:screen===s?"#fff":t.muted,cursor:"pointer"}}>{labels[s]}</button>)}
      </div>
    </div>
  );
}

function Nav({onBack,onClose,title}){return(
  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 16px 4px",minHeight:"44px"}}>
    {onBack?<button onClick={onBack} style={{background:"none",border:"none",cursor:"pointer",padding:"8px",margin:"-8px",display:"flex"}} aria-label="Back"><svg width="24" height="24" fill="none" stroke={t.fg} strokeWidth="2" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeLinecap="round" strokeLinejoin="round"/></svg></button>:<div style={{width:"40px"}}/>}
    {title&&<span style={{fontFamily:f,fontSize:"17px",fontWeight:600,color:t.fg}}>{title}</span>}
    {onClose?<button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",padding:"8px",margin:"-8px",display:"flex"}} aria-label="Close"><svg width="24" height="24" fill="none" stroke={t.fg} strokeWidth="2" viewBox="0 0 24 24"><path d="M18 6L6 18M6 6l12 12" strokeLinecap="round"/></svg></button>:<div style={{width:"40px"}}/>}
  </div>
)}

function Avatar({initials,size=44,bg="#fff3",color="#fff"}){return(
  <div style={{width:size,height:size,borderRadius:"50%",background:bg,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:f,fontSize:size*0.32,fontWeight:700,color,flexShrink:0,backdropFilter:"blur(10px)",border:"1px solid rgba(255,255,255,0.3)"}}>{initials}</div>
)}

function Badge({label,bg,color}){return(
  <span style={{display:"inline-flex",padding:"4px 12px",borderRadius:"9999px",background:bg,color,fontFamily:f,fontSize:"13px",fontWeight:600}}>{label}</span>
)}

// Card component — white rounded card on gray bg
function Card({children,style={},onClick}){return(
  <div onClick={onClick} style={{background:t.card,borderRadius:"16px",padding:"16px",marginBottom:"12px",boxShadow:"0 1px 3px rgba(0,0,0,0.04)",cursor:onClick?"pointer":"default",...style}}>{children}</div>
)}

function Footer(){return(
  <div style={{padding:"32px 20px 40px",marginTop:"auto"}}>
    <div style={{display:"flex",justifyContent:"center",marginBottom:"12px"}}>
      <Logo size={18} color={t.muted}/>
    </div>
    <div style={{display:"flex",justifyContent:"center",gap:"16px",marginBottom:"12px",flexWrap:"wrap"}}>
      {["About","Terms","Privacy","Support"].map(link=>(
        <span key={link} style={{fontFamily:f,fontSize:"13px",color:t.muted,cursor:"pointer",fontWeight:500}}>{link}</span>
      ))}
    </div>
    <p style={{fontFamily:f,fontSize:"11px",color:"#C7C7CC",margin:0,textAlign:"center"}}>© 2026 Kliques. All rights reserved.</p>
  </div>
)}

// ═══════════════════════════════════════════
// OFFCANVAS MENU
// ═══════════════════════════════════════════
function SideMenu({open,onClose,items,active,onNav,userName,userInitials}){
  if(!open) return null;
  return(
    <div style={{position:"absolute",inset:0,zIndex:50,display:"flex"}}>
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.4)"}}/>
      <div style={{position:"relative",width:"280px",height:"100%",background:t.card,display:"flex",flexDirection:"column",boxShadow:"4px 0 24px rgba(0,0,0,0.1)",animation:"slideIn 0.25s ease-out"}}>
        <div style={{padding:"24px 20px 20px",borderBottom:"0.5px solid "+t.divider}}>
          <div style={{display:"flex",alignItems:"center",gap:"12px"}}>
            <Avatar initials={userInitials} size={44} bg={t.accentLight} color={t.accent}/>
            <div><p style={{fontFamily:f,fontSize:"16px",fontWeight:700,color:t.fg,margin:0}}>{userName}</p><Logo size={14}/></div>
          </div>
        </div>
        <div style={{flex:1,overflowY:"auto",padding:"8px 0"}}>
          {items.map(item=>(
            <button key={item.id} onClick={()=>{onNav(item.id);onClose()}} style={{
              display:"flex",alignItems:"center",gap:"14px",
              padding:"14px 20px",background:active===item.id?t.accentLight:"transparent",
              border:"none",cursor:"pointer",width:"100%",textAlign:"left",
              borderRight:active===item.id?"3px solid "+t.accent:"3px solid transparent",
            }}>
              <svg width="22" height="22" fill={active===item.id?t.accent:"none"} stroke={active===item.id?t.accent:t.muted} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24"><path d={item.d}/></svg>
              <span style={{fontFamily:f,fontSize:"15px",fontWeight:active===item.id?700:500,color:active===item.id?t.fg:t.muted}}>{item.label}</span>
              {item.badge&&<div style={{width:"8px",height:"8px",borderRadius:"50%",background:t.accent,marginLeft:"auto"}}/>}
              {item.count&&<span style={{marginLeft:"auto",padding:"2px 8px",borderRadius:"9999px",background:t.accent,color:"#fff",fontFamily:f,fontSize:"11px",fontWeight:700}}>{item.count}</span>}
            </button>
          ))}
        </div>
        <div style={{padding:"16px 20px",borderTop:"0.5px solid "+t.divider}}>
          <p style={{fontFamily:f,fontSize:"12px",color:t.muted,margin:0,textAlign:"center"}}>kliques · relationship OS</p>
        </div>
      </div>
    </div>
  );
}

function Logo({size=18,color=t.accent}){return(
  <span style={{fontFamily:"'Playfair Display',Georgia,serif",fontSize:size+"px",fontWeight:700,color,letterSpacing:"-0.5px"}}>kliques</span>
)}

function MenuBtn({onClick,white}){return(
  <button onClick={onClick} style={{background:"none",border:"none",cursor:"pointer",padding:"8px",margin:"-8px",display:"flex"}} aria-label="Open menu">
    <svg width="24" height="24" fill="none" stroke={white?"#fff":t.fg} strokeWidth="2" viewBox="0 0 24 24"><path d="M4 6h16M4 12h16M4 18h16" strokeLinecap="round"/></svg>
  </button>
)}

// Gradient header — warm gradient with title overlay
function GradientHeader({onMenu,title,subtitle,right,children}){return(
  <div style={{background:grad,padding:"0 20px",paddingBottom:"48px",borderRadius:"0 0 28px 28px",marginBottom:"-20px",position:"relative",zIndex:1}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"16px",paddingTop:"4px"}}>
      <MenuBtn onClick={onMenu} white/>
      <Logo size={20} color="#fff"/>
      {right||<div style={{width:"40px"}}/>}
    </div>
    {title&&<h1 style={{fontFamily:f,fontSize:"30px",fontWeight:700,color:"#fff",margin:"0 0 4px"}}>{title}</h1>}
    {subtitle&&<p style={{fontFamily:f,fontSize:"15px",color:"rgba(255,255,255,0.8)",margin:0}}>{subtitle}</p>}
    {children}
  </div>
)}

