    <Card onClick={()=>go("p_bookings")} style={{display:"flex",alignItems:"center",gap:"12px",background:t.accentLight,cursor:"pointer"}}><div style={{width:"36px",height:"36px",borderRadius:"10px",background:t.accent,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><span style={{color:"#fff",fontFamily:f,fontSize:"16px",fontWeight:700}}>3</span></div><div><p style={{fontFamily:f,fontSize:"15px",fontWeight:600,color:t.fg,margin:0}}>Pending booking requests</p><p style={{fontFamily:f,fontSize:"13px",color:t.muted,margin:"2px 0 0"}}>Tap to review and accept</p></div></Card>
