// P2: Bookings
function PBookings({go,onMenu}){const [bookings,setBookings]=useState([{id:1,client:"Emma Wilson",initials:"EW",svc:"1-on-1 Vocal Lesson",date:"Thu, Mar 20 at 11:00 AM",dur:"1 hr",price:"$85",note:"I'd like to work on my high notes.",status:"pending"},{id:2,client:"Ryan Park",initials:"RP",svc:"Performance Coaching",date:"Fri, Mar 21 at 2:00 PM",dur:"45 min",price:"$95",note:"",status:"pending"},{id:3,client:"Nadia Khan",initials:"NK",svc:"Group Class",date:"Sat, Mar 22 at 10:00 AM",dur:"1 hr, 30 min",price:"$45",note:"My friend Maya will also be joining.",status:"pending"}]);const updateStatus=(id,s)=>setBookings(prev=>prev.map(b=>b.id===id?{...b,status:s}:b));const pending=bookings.filter(b=>b.status==="pending");const handled=bookings.filter(b=>b.status!=="pending");return(<div style={{height:"100%",background:t.bg,overflowY:"auto",display:"flex",flexDirection:"column"}}><GradientHeader onMenu={onMenu} title="Bookings" subtitle={pending.length+" pending · "+handled.length+" reviewed"}/><div style={{padding:"32px 16px 0",flex:1,display:"flex",flexDirection:"column"}}>{pending.map(b=><Card key={b.id}><div style={{display:"flex",alignItems:"center",gap:"12px",marginBottom:"12px"}}><Avatar initials={b.initials} size={44} bg={t.accentLight} color={t.accent}/><div style={{flex:1}}><p style={{fontFamily:f,fontSize:"16px",fontWeight:600,color:t.fg,margin:"0 0 2px"}}>{b.client}</p><p style={{fontFamily:f,fontSize:"13px",color:t.muted,margin:0}}>{b.date}</p></div><span style={{fontFamily:f,fontSize:"16px",fontWeight:700,color:t.fg}}>{b.price}</span></div><div style={{padding:"12px",borderRadius:"10px",background:t.bg,marginBottom:"12px"}}><p style={{fontFamily:f,fontSize:"14px",fontWeight:600,color:t.fg,margin:"0 0 2px"}}>{b.svc}</p><p style={{fontFamily:f,fontSize:"13px",color:t.muted,margin:0}}>{b.dur}</p></div>{b.note&&<div style={{padding:"12px",borderRadius:"10px",background:t.callout,marginBottom:"12px"}}><p style={{fontFamily:f,fontSize:"14px",color:t.fg,margin:0,lineHeight:1.5}}>{b.note}</p></div>}<div style={{display:"flex",gap:"8px"}}><button onClick={()=>updateStatus(b.id,"rejected")} style={{flex:1,padding:"12px",borderRadius:"12px",border:"1px solid "+t.divider,background:t.card,fontFamily:f,fontSize:"14px",fontWeight:600,color:t.fg,cursor:"pointer"}}>Decline</button><button onClick={()=>updateStatus(b.id,"accepted")} style={{flex:2,padding:"12px",borderRadius:"12px",border:"none",background:t.ctaBg,color:t.ctaText,fontFamily:f,fontSize:"14px",fontWeight:700,cursor:"pointer"}}>Accept</button></div></Card>)}{pending.length===0&&<Card style={{textAlign:"center",padding:"40px 16px"}}><div style={{width:"56px",height:"56px",borderRadius:"50%",background:t.successLight,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 12px"}}><svg width="28" height="28" fill="none" stroke={t.success} strokeWidth="2" viewBox="0 0 24 24"><path d="M5 13l4 4L19 7" strokeLinecap="round" strokeLinejoin="round"/></svg></div><p style={{fontFamily:f,fontSize:"17px",fontWeight:600,color:t.fg,margin:"0 0 4px"}}>All caught up!</p><p style={{fontFamily:f,fontSize:"14px",color:t.muted,margin:0}}>No pending requests</p></Card>}{handled.length>0&&<><p style={{fontFamily:f,fontSize:"15px",fontWeight:700,color:t.muted,margin:"8px 4px 12px"}}>Reviewed</p>{handled.map(b=><Card key={b.id} style={{display:"flex",alignItems:"center",gap:"12px",opacity:0.6}}><Avatar initials={b.initials} size={40} bg={t.accentLight} color={t.accent}/><div style={{flex:1}}><p style={{fontFamily:f,fontSize:"15px",fontWeight:500,color:t.fg,margin:0}}>{b.client}</p></div><Badge label={b.status==="accepted"?"Accepted":"Declined"} bg={b.status==="accepted"?t.successLight:t.dangerLight} color={b.status==="accepted"?"#15803D":t.danger}/></Card>)}</>}<Footer/></div></div>)}

