function PCalendar({go,onMenu}){const [monthOffset,setMonthOffset]=useState(0);const [selectedDay,setSelectedDay]=useState(19);const today={day:19,month:2,year:2026};const monthNames=["January","February","March","April","May","June","July","August","September","October","November","December"];const dayLabels=["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];const getMonth=()=>{let m=today.month+monthOffset;let y=today.year;while(m>11){m-=12;y++}while(m<0){m+=12;y--}return{month:m,year:y}};const{month,year}=getMonth();const daysInMonth=new Date(year,month+1,0).getDate();const firstDow=(new Date(year,month,1).getDay()+6)%7;const isCurrentMonth=monthOffset===0;const bookings={17:[{name:"Kai T.",svc:"Vocal Lesson",time:"11:00 AM",dur:"1 hr"}],19:[{name:"Sarah M.",svc:"Vocal Lesson",time:"10:30 AM",dur:"1 hr"},{name:"Kai T.",svc:"Performance Coaching",time:"12:00 PM",dur:"45 min"},{name:"Lisa R.",svc:"Group Class",time:"2:00 PM",dur:"1.5 hr"},{name:"David P.",svc:"Song Arrangement",time:"4:30 PM",dur:"30 min"}],20:[{name:"Sarah M.",svc:"Vocal Lesson",time:"2:00 PM",dur:"1 hr"}],22:[{name:"Lisa R.",svc:"Vocal Lesson",time:"10:00 AM",dur:"1 hr"}],25:[{name:"David P.",svc:"Vocal Lesson",time:"3:00 PM",dur:"1 hr"}]};const daysWithBookings=isCurrentMonth?Object.keys(bookings).map(Number):[];const daySchedule=isCurrentMonth?(bookings[selectedDay]||[]):[];const dayNames=["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"];const selectedDow=new Date(year,month,selectedDay).getDay();const selectedLabel=dayNames[selectedDow]+", "+monthNames[month].slice(0,3)+" "+selectedDay;return(<div style={{height:"100%",background:t.bg,overflowY:"auto",display:"flex",flexDirection:"column"}}><GradientHeader onMenu={onMenu} title="Calendar"/><div style={{padding:"32px 16px 0",flex:1,display:"flex",flexDirection:"column"}}><Card><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"16px"}}><button onClick={()=>{setMonthOffset(monthOffset-1);setSelectedDay(1)}} style={{width:"32px",height:"32px",borderRadius:"50%",border:"1px solid "+t.divider,background:t.bg,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><svg width="16" height="16" fill="none" stroke={t.fg} strokeWidth="2" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeLinecap="round" strokeLinejoin="round"/></svg></button><span style={{fontFamily:f,fontSize:"17px",fontWeight:700,color:t.fg}}>{monthNames[month]} {year}</span><button onClick={()=>{setMonthOffset(monthOffset+1);setSelectedDay(1)}} style={{width:"32px",height:"32px",borderRadius:"50%",border:"1px solid "+t.divider,background:t.bg,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><svg width="16" height="16" fill="none" stroke={t.fg} strokeWidth="2" viewBox="0 0 24 24"><path d="M9 5l7 7-7 7" strokeLinecap="round" strokeLinejoin="round"/></svg></button></div><div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:"0",marginBottom:"4px"}}>{dayLabels.map(d=><div key={d} style={{textAlign:"center",fontFamily:f,fontSize:"12px",fontWeight:600,color:t.muted,padding:"4px 0"}}>{d}</div>)}</div><div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:"2px"}}>{Array.from({length:firstDow}).map((_,i)=><div key={"e"+i}/>)}{Array.from({length:daysInMonth}).map((_,i)=>{const day=i+1;const isSelected=day===selectedDay;const isToday=isCurrentMonth&&day===today.day;const hasBooking=daysWithBookings.includes(day);return(<button key={day} onClick={()=>setSelectedDay(day)} style={{width:"100%",aspectRatio:"1",borderRadius:"50%",border:"none",background:isSelected?t.accent:"transparent",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",position:"relative",padding:0,outline:isToday&&!isSelected?"2px solid "+t.accent:"none",outlineOffset:"-2px"}}><span style={{fontFamily:f,fontSize:"14px",fontWeight:isSelected||isToday?700:400,color:isSelected?"#fff":t.fg}}>{day}</span>{hasBooking&&<div style={{position:"absolute",bottom:"3px",width:"4px",height:"4px",borderRadius:"50%",background:isSelected?"#fff":t.accent}}/>}</button>)})}</div></Card><p style={{fontFamily:f,fontSize:"16px",fontWeight:700,color:t.fg,margin:"4px 4px 12px"}}>{selectedLabel}</p>{daySchedule.length===0?<Card style={{textAlign:"center",padding:"32px 16px"}}><p style={{fontFamily:f,fontSize:"15px",color:t.muted,margin:0}}>No bookings this day</p></Card>:daySchedule.map((s,i)=><Card key={i} onClick={()=>go("p_appt_detail")} style={{display:"flex",alignItems:"center",gap:"12px",cursor:"pointer"}}><div style={{width:"4px",height:"40px",borderRadius:"2px",background:t.accent,flexShrink:0}}/><div style={{flex:1}}><p style={{fontFamily:f,fontSize:"15px",fontWeight:600,color:t.fg,margin:"0 0 2px"}}>{s.name}</p><p style={{fontFamily:f,fontSize:"13px",color:t.muted,margin:0}}>{s.svc} · {s.dur}</p></div><span style={{fontFamily:f,fontSize:"14px",fontWeight:600,color:t.fg}}>{s.time}</span></Card>)}<Footer/></div></div>)}

